#include <iostream>

void doubleValue(int& num) {
    num = num * 2;
}

int main() {
    int test_values[] = {5, 0, -3};
    for (int i = 0; i < sizeof(test_values) / sizeof(test_values[0]); ++i) {
        int num = test_values[i];
        doubleValue(num);
        std::cout << num << std::endl;
    }
    return 0;
}
